// 获取文档段落总数并计算分批大小
var doc = Application.ActiveDocument;
var paras = doc.Paragraphs;
var totalParas = paras.Count;
var batchCount = Math.ceil(totalParas / 500); // 每批 500 段
return { totalParas: totalParas, batchCount: batchCount, batchSize: 500 };

// 分批扫描标题、图、表、公式编号（前 500 段）
var doc = Application.ActiveDocument;
var paras = doc.Paragraphs;
var maxPara = Math.min(500, paras.Count);
var headings = [], figures = [], tables = [], formulas = [];
for (var i = 1; i <= maxPara; i++) {
    var text = paras(i).Range.Text.replace(/\r\n$/, '');
    if (/^第 [一二三四五六七八九十]+章\s/.test(text)) {
        headings.push({ index: i, text: text, type: 'h1' });
    } else if (/^\d+\.\d+\s/.test(text)) {
        headings.push({ index: i, text: text, type: 'h2' });
    } else if (/^图\d+-?\d+\s/.test(text)) {
        figures.push({ index: i, text: text });
    } else if (/^表\d+-?\d+\s/.test(text)) {
        tables.push({ index: i, text: text });
    } else if (/^\(\d+-?\d+\)\s*$/.test(text.trim())) {
        formulas.push({ index: i, text: text });
    }
}
return { headings: headings.length, figures: figures.length, tables: tables.length, formulas: formulas.length, sampleHeadings: headings.slice(0, 5), sampleFigures: figures.slice(0, 3) };

